import type { StateCreator } from 'zustand';
import { InvoiceCashbackPermissionState, PermissionStatus } from '../models';

export interface InvoiceCashbackPermissionActions {
  setStatus: (status: PermissionStatus) => void;
  setHasRedeemed: (hasRedeemed: boolean) => void;
  reset: () => void;
}

export interface InvoiceCashbackPermissionSlice {
  invoiceCashbackPermission: InvoiceCashbackPermissionState;
  invoiceCashbackPermissionActions: InvoiceCashbackPermissionActions;
}

const initialState: InvoiceCashbackPermissionState = {
  status: PermissionStatus.IDLE,
  hasRedeemed: null,
};

export const createInvoiceCashbackPermissionSlice: StateCreator<
  InvoiceCashbackPermissionSlice,
  [],
  [],
  InvoiceCashbackPermissionSlice
> = (set) => ({
  invoiceCashbackPermission: initialState,
  invoiceCashbackPermissionActions: {
    setStatus: (status: PermissionStatus) =>
      set((state) => ({
        invoiceCashbackPermission: { ...state.invoiceCashbackPermission, status },
      })),
    setHasRedeemed: (hasRedeemed: boolean) =>
      set((state) => ({
        invoiceCashbackPermission: {
          ...state.invoiceCashbackPermission,
          hasRedeemed,
          status: PermissionStatus.SUCCESS,
        },
      })),
    reset: () =>
      set({
        invoiceCashbackPermission: initialState,
      }),
  },
});

