import { useCallback } from 'react';
import { getClientNRC } from '../../hooks/useSelectors';
import {
  checkHasRedeemed as checkHasRedeemedService,
  markAsRedeemed as markAsRedeemedService,
} from '../services';
import { useRootStore } from '~/store';
import { PermissionStatus } from '../models';

export function useInvoiceCashbackPermission() {
  const accountId = getClientNRC();

  const { hasRedeemed, status } = useRootStore((state) => state.invoiceCashbackPermission);

  const isLoading = status === PermissionStatus.LOADING;
  const isError = status === PermissionStatus.ERROR;

  const checkHasRedeemed = useCallback(
    async ({ forceRefresh = false }: { forceRefresh?: boolean } = {}): Promise<boolean> => {
      if (hasRedeemed !== null && !forceRefresh) {
        return hasRedeemed;
      }

      if (!accountId) {
        throw new Error('Expected accountId to be defined.');
      }

      return checkHasRedeemedService(accountId);
    },
    [accountId, hasRedeemed]
  );

  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    if (!accountId) {
      return false;
    }

    return markAsRedeemedService(accountId);
  }, [accountId]);

  return {
    hasRedeemed,
    isLoading,
    isError,
    checkHasRedeemed,
    markAsRedeemed,
  };
}

import { StateCreator } from "zustand";
import {
  createParameterPointsProgramSlice,
  createPointsExtractSlice,
  ParameterPointsProgramSlice,
  PointsExtractSlice,
  createAirlineMilesSlice,
  AirlineMilesSlice,
  createMarketplaceSlice,
  MarketplaceSlice,
  createInvoiceCashbackPermissionSlice,
  InvoiceCashbackPermissionSlice,
  createPointsProductsSlice,
  PointsProductsSlice,
  createRescueSlice,
  RescueSlice,
} from "../services/store";

export type RewardProgramRootStore =
  ParameterPointsProgramSlice &
  PointsExtractSlice &
  AirlineMilesSlice &
  MarketplaceSlice &
  InvoiceCashbackPermissionSlice &
  PointsProductsSlice &
  RescueSlice;
export type Slice<T> = StateCreator<RewardProgramRootStore, [], [], T>;
export const asSlice = <T>(slice: StateCreator<RewardProgramRootStore, [], [], T>) => slice as Slice<T>;

export function setSlicesRewardProgram<T extends RewardProgramRootStore>(...a: Parameters<Slice<T>>) {
  return {
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
    ...asSlice<InvoiceCashbackPermissionSlice>(createInvoiceCashbackPermissionSlice)(...a),
    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
    ...asSlice<RescueSlice>(createRescueSlice)(...a),
  };
}

